return [{
  json: {
    config: {
      enableTelegram: true,
      enableWhatsApp: false,
      enableTwitter: true,
      telegramChatId: '-3432705907',
      whatsappChatId: 'YOUR_WHATSAPP_BROADCAST_ID',
      googleSheetId: '1u8LUepeWdAP5hMUtGCk4yQ3j_HxxGmwSvJEg4982XDk',
      sheetName: 'Deals',
      aliAppKey: 'YOUR_ALI_APP_KEY',
      aliAppSecret: 'YOUR_ALI_APP_SECRET',
      aliTrackingId: 'dealplugjamaica',
      aliEndpoint: 'https://api-sg.aliexpress.com/sync',
      xDailyLimitPerRun: 5
    }
  }
}];

const cfg = $json.config;
const categories = [
  {
    category: 'Tech Deals',
    aliKeywords: 'phone case charging cable earbuds',
    aliCategoryId: '509'
  },
  {
    category: 'Home & LED Finds',
    aliKeywords: 'LED strip light motion sensor kitchen gadget',
    aliCategoryId: '200003498'
  },
  {
    category: 'Gift Ideas Under $10',
    aliKeywords: 'jewelry keychain mini speaker gift',
    aliCategoryId: '207'
  },
  {
    category: 'Bulk Deals for Businesses',
    aliKeywords: 'label sticker packaging tape bag',
    aliCategoryId: '200003655'
  }
];
return categories.map(c => ({ json: { ...c, config: cfg } }));

// Convert manually-added Temu rows from Google Sheet into deal format.
// You add Temu deals to the Deals_Raw sheet -> n8n picks them up and posts them.
const cfg = $('Define Categories').first().json.config;

// If no row data, skip
if (!$json.Title && !$json.title) return [];

const title        = ($json.Title || $json.title || '').trim();
const price        = Number($json['Price (USD)'] || $json.price || 0);
const rating       = Number($json.Rating || $json.rating || 4.5);
const orders       = Number($json.Orders || $json.orders || 100);
const affiliateUrl = ($json['Affiliate Link'] || $json.affiliateUrl || '').trim();
const imageUrl     = ($json['Image URL'] || $json.imageUrl || '').trim();
const category     = ($json.Category || $json.category || 'General').trim();
const commission   = ($json['Commission %'] || $json.commissionRate || '').trim();

// Skip rows with missing data or out-of-range prices
if (!title || !affiliateUrl || price <= 0 || price > 50) return [];

return [{
  json: {
    source: 'temu_sheet',
    sourceProductId: affiliateUrl,
    duplicateKey: `temu_sheet:${affiliateUrl}`,
    title,
    price,
    currency: 'USD',
    rating,
    orders,
    imageUrl,
    productUrl: affiliateUrl,
    affiliateUrl,
    category,
    commissionRate: commission,
    scrapedAt: new Date().toISOString(),
    score: 0,
    priceBucket: price <= 5 ? 'UNDER_5' : (price <= 10 ? 'UNDER_10' : 'UNDER_15'),
    sourcePriority: 1,
    config: cfg
  }
}];

const crypto = require('crypto');
const cfg = $json.config;
const timestamp = new Date().toISOString().replace('T', ' ').replace('Z', '');
const params = {
  app_key: cfg.aliAppKey,
  category_ids: $json.aliCategoryId,
  fields: 'commission_rate,sale_price,product_title,product_main_image_url,product_detail_url,evaluate_rate,lastest_volume,product_id',
  format: 'json',
  keywords: $json.aliKeywords,
  max_sale_price: '15',
  method: 'aliexpress.affiliate.product.query',
  page_no: '1',
  page_size: '20',
  sign_method: 'md5',
  sort: 'SALE_PRICE_ASC',
  target_currency: 'USD',
  timestamp,
  tracking_id: cfg.aliTrackingId,
  v: '2.0'
};

const sortedKeys = Object.keys(params).sort();
let signString = '';
for (const key of sortedKeys) {
  signString += key + params[key];
}
const sign = crypto
  .createHash('md5')
  .update(cfg.aliAppSecret + signString + cfg.aliAppSecret, 'utf8')
  .digest('hex')
  .toUpperCase();

return [{
  json: {
    config: cfg,
    category: $json.category,
    aliParams: { ...params, sign }
  }
}];

const cfg = $('Build AliExpress Signed Params').item.json.config;
const category = $('Build AliExpress Signed Params').item.json.category;
const result =
  $json?.aliexpress_affiliate_product_query_response?.resp_result?.result?.products?.product || [];
const products = Array.isArray(result) ? result : [];
return products
  .filter(p => Number(p.sale_price || 0) > 0)
  .map(p => ({
    json: {
      source: 'aliexpress',
      sourceProductId: String(p.product_id || p.product_detail_url || p.product_title),
      duplicateKey: `aliexpress:${String(p.product_id || p.product_detail_url || p.product_title)}`,
      title: p.product_title,
      price: Number(Number(p.sale_price || 0).toFixed(2)),
      currency: 'USD',
      rating: Number(Number(p.evaluate_rate || 0).toFixed(1)),
      orders: Number(p.lastest_volume || 0),
      imageUrl: p.product_main_image_url || '',
      productUrl: p.product_detail_url || '',
      affiliateUrl: p.product_detail_url || '',
      category,
      commissionRate: p.commission_rate || '',
      scrapedAt: new Date().toISOString(),
      score: 0,
      priceBucket: Number(p.sale_price || 0) <= 5 ? 'UNDER_5' : (Number(p.sale_price || 0) <= 10 ? 'UNDER_10' : 'UNDER_15'),
      sourcePriority: 2,
      config: cfg
    }
  }));

const items = $input.all().map(i => i.json);
const map = new Map();

for (const d of items) {
  if (!d.duplicateKey) continue;
  const existing = map.get(d.duplicateKey);
  if (!existing || Number(d.orders || 0) > Number(existing.orders || 0)) {
    const price      = Number(d.price || 0);
    const rating     = Number(d.rating || 0);
    const orders     = Number(d.orders || 0);
    const commission = Number(String(d.commissionRate || '0').replace('%', '')) || 0;
    const visualBoost   = /light|led|speaker|case|gift|gadget/i.test(d.title || '') ? 10 : 0;
    const underFiveBoost = price <= 5 ? 25 : 0;
    const score = Math.round(
      (Math.min(orders, 5000) / 100) +
      (rating * 12) +
      ((15 - Math.min(price, 15)) * 5) +
      (commission * 2) +
      visualBoost +
      underFiveBoost
    );
    d.score = score;
    map.set(d.duplicateKey, d);
  }
}

const twitterHooks = [
  '🔥 DEAL ALERT 🇯🇲',
  '💰 Jamaicans, listen up.',
  '😳 This price is CRIMINAL.',
  '⚡ Quick deal drop:',
  '🛒 Don\'t scroll past this.'
];

const tiktokHooks = [
  `This is WHY everyone is sleeping on this 😳`,
  `POV: You found a cheat code for shopping 🔥`,
  `Stop overpaying for this RIGHT NOW`,
  `Jamaicans NEED to know about this deal`,
  `I can't believe this price 😭`
];

const hashtags = [
  '#DealPlugJamaica #Jamaica #OnlineDeals #SaveMoney',
  '#DealPlug #Jamaica #CheapFinds #Deals',
  '#JamaicaShopping #DealAlert #SaveBig #Jamaica',
  '#DealPlugJA #BudgetShopping #Jamaica #Deals'
];

return Array.from(map.values())
  .filter(d => d.price > 0 && d.price <= 15)
  .sort((a, b) => b.score - a.score)
  .slice(0, 25)
  .map(d => {
    const hook    = twitterHooks[Math.floor(Math.random() * twitterHooks.length)];
    const tikHook = tiktokHooks[Math.floor(Math.random() * tiktokHooks.length)];
    const tags    = hashtags[Math.floor(Math.random() * hashtags.length)];
    const shortTitle = String(d.title).slice(0, 60);

    const tiktokCaption   = `${tikHook}\n\n📦 ${shortTitle}...\n💰 Only $${d.price} USD\n⭐ ${d.rating} | ${d.orders}+ sold\n\nLink in bio 👆 #DealPlugJamaica`;
    const whatsappMessage = `🔥 *DEAL ALERT* 🔥\n\n${String(d.title).slice(0, 80)}\n\n💰 Price: $${d.price} USD\n⭐ Rating: ${d.rating}\n📦 ${d.orders}+ people already bought this\n\n👇 Get it here:\n${d.affiliateUrl}\n\n_DealPlug Jamaica 🇯🇲_`;
    const telegramMessage = `🔥 <b>DEAL ALERT</b>\n\n${String(d.title).slice(0, 100)}\n💰 <b>$${d.price}</b> USD\n⭐ ${d.rating} | ${d.orders}+ sold\n📦 ${d.category}\n\n👉 <a href="${d.affiliateUrl}">Buy here</a>`;
    const tweet           = `${hook}\n\n${shortTitle}...\n💰 $${d.price} · ⭐ ${d.rating} · ${d.orders}+ sold\n\n${tags}\n\n${d.affiliateUrl}`.slice(0, 280);

    return {
      json: {
        ...d,
        tiktokCaption,
        whatsappMessage,
        telegramMessage,
        tweet,
        hook: tikHook,
        postedTelegram: 'No',
        postedWhatsApp: 'No',
        postedTwitter:  'No'
      }
    };
  });
